import{_ as t,o as e,c as o,ag as r}from"./chunks/framework.DQe9aj1R.js";const m=JSON.parse('{"title":"GameCanvas とは","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1776098746000}'),d={name:"guide/getting-started.md"};function i(n,a,s,l,c,h){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="gamecanvas-とは" tabindex="-1">GameCanvas とは <a class="header-anchor" href="#gamecanvas-とは" aria-label="Permalink to &quot;GameCanvas とは&quot;">​</a></h1><p><strong>GameCanvas for Unity</strong> は、慶應義塾大学『スマートデバイスプログラミング』にて教材として使われている 2D ゲームフレームワーク です。</p><p>プログラミング初心者でも、スマートデバイス向けアプリケーションを楽しく開発できる環境を目指して開発されました。</p><h2 id="特徴" tabindex="-1">特徴 <a class="header-anchor" href="#特徴" aria-label="Permalink to &quot;特徴&quot;">​</a></h2><ul><li><strong>シンプルな API</strong> — 座標指定の描画や入力取得など、ゲーム作りに必要な機能が 1 つの <code>IGameCanvas</code> インターフェイスに集約されています。</li><li><strong>型安全なリソース参照</strong> — 画像・音声・フォントは <code>GcImage</code> / <code>GcSound</code> / <code>GcFont</code> といった型安全な struct 経由で扱います。</li><li><strong>Unity Editor ベース</strong> — 実機に書き出す前に、Unity Editor 上で動作確認できます。</li><li><strong>iOS / Android 対応</strong> — 同じコードで両プラットフォームに書き出せます。</li></ul><h2 id="構成" tabindex="-1">構成 <a class="header-anchor" href="#構成" aria-label="Permalink to &quot;構成&quot;">​</a></h2><p>プロジェクトは次のように分かれています。</p><table tabindex="0"><thead><tr><th>パス</th><th>役割</th></tr></thead><tbody><tr><td><code>Assets/Game.cs</code></td><td>学生が編集するゲームロジック (<code>GameBase</code> を継承)</td></tr><tr><td><code>Packages/jp.ac.keio.sfc.sdp/</code></td><td>フレームワーク本体 (UPM パッケージ)</td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><ul><li><a href="./installation">インストール手順</a> を確認する</li><li><a href="/GameCanvas-Unity/api/">API リファレンス</a> を読む</li><li><a href="./compatibility">旧 API 対応表</a> で古いコードを移行する</li></ul>',10)])])}const p=t(d,[["render",i]]);export{m as __pageData,p as default};
